head.script:
scwin.retrieveDetailYn = "notYet";

scwin.addFlag = false;
scwin.modFlag = false;

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	rd_useYn.setValue("1");

    $c.gus.cfDisableObjects([ ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy
					        , acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2, acb_lux_degClsCd
                            , ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt
					        , ed_txt_insrTrf, ica_em_cutShedDt, rd_useYn, ed_txt_rmk ]);

    const codeOptions = [
        { grpCd : "JA060", compID : "acb_eqNrmCd,gr_results:ton" }
      , { grpCd : "JA010", compID : "acb_lux_bizTypCd" }
      , { grpCd : "JA080", compID : "acb_lux_trfAdptCd" }
      , { grpCd : "JA090", compID : "acb_lux_degClsCd" }
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    rd_useYn.setValue("1");
    $c.gus.cfDisableObjects([ ed_clntNo_rslts, txt_clntNm_rslts, em_insrTermFrom, em_insrTermTo ]);
};

//-------------------------------------------------------------------------
// function name : f_FieldClear
// function desc : 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects([tbl_cndArea]);
};


//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    ds_results.removeAll();
	ds_clnt.removeAll();
	ds_manager.removeAll();

	//tr_retrieve.post();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        totalRowsResults.setValue(ds_results.getRowCount());

        if( ds_results.getRowCount() == 0 ) {
            $c.win.alert("조회된 데이터가 없습니다.");
            //$c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return false;
        } else {
            gr_results.setFocusedCell(0, 0);
            scwin.f_retrieve_clntAndManager();
            $c.gus.cfDisableObjects([ ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd
                                    , ed_txt_stdFleffcncy, ed_clntNo_rslts, txt_clntNm_rslts
                                    , acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2, acb_lux_degClsCd
                                    , ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt
                                    , ed_txt_insrTrf, ica_em_cutShedDt, em_insrTermFrom, em_insrTermTo, rd_useYn, ed_txt_rmk ]);
        }
    }
};

scwin.f_retrieve_clntAndManager = function () {
	dma_cond_clntManager.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));

	//tr_retrieve_clntAndMngnr.post();
    $c.sbm.execute(sbm_retrieve_clntAndMngnr);
};

scwin.sbm_retrieve_clntAndMngnr_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        totalRowsClnt.setValue(ds_clnt.getRowCount());
        totalRowsManager.setValue(ds_manager.getRowCount());
        scwin.retrieveDetailYn = "yes";
    }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    //저장을 무조건 타도록
	ds_results.setCellData(ds_results.getRowPosition(), "modDtm", "1");

	for( var i = 0; i < ds_results.getRowCount(); i++ ) {
		if(ds_results.getRowStatusValue(i) == "1" || ds_results.getRowStatusValue(i) == "2" || ds_results.getRowStatusValue(i) == "3") {
			if(ds_results.getCellData(i, "vehclNo") == "") {
				$c.win.alert("차량번호는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if(ds_results.getCellData(i, "ton") == "") {
				$c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 톤은 필수 입력 항목 입니다.");
				return false;
				break
			}
			if(ds_results.getCellData(i, "clntNo") == "") {
				$c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 소속거래처는 필수 입력 항목 입니다.");
				return false;
				break
			}
			if(ds_results.getCellData(i, "bizTypCd") == "") {
				$c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 업종코드는 필수 입력 항목 입니다.");
				return false;
				break
			}
			if(ds_results.getCellData(i, "trfAdptCd") == "") {
				$c.win.alert("차량번호 "+ds_results.getCellData(i, "vehclNo")+"의 요율적용코드는 필수 입력 항목 입니다.");
				return false;
				break
			}

			if(ds_results.getCellData(i, "useYn") == 1 && ds_manager.getRowCount() == 0) {
				$c.win.alert("매니저 정보를 입력해야 합니다.");
				return false;
			}
		}
	}

	for(var i = 0; i < ds_clnt.getRowCount(); i++) {
		if(ds_clnt.getRowStatusValue(i) == "1" || ds_clnt.getRowStatusValue(i) == "2" || ds_clnt.getRowStatusValue(i) == "3" ) {
			if(ds_clnt.getCellData(i, "clntNo") == "") {
				$c.win.alert("매출거래처는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if(ds_clnt.getCellData(i, "ctrtStDt") == "") {
				$c.win.alert("매출거래처의 적용일자FROM은  필수 입력 항목 입니다.");
				return false;
				break;
			}
			if(ds_clnt.getCellData(i, "ctrtEndDt") == "") {
				$c.win.alert("매출거래처의 적용일자TO는  필수 입력 항목 입니다.");
				return false;
				break;
			}
		}
	}

	for(var i = 0; i < ds_manager.getRowCount(); i++) {
		if(ds_manager.getRowStatusValue(i) == "1" || ds_manager.getRowStatusValue(i) == "2" || ds_manager.getRowStatusValue(i) == "3" ) {
			if(ds_manager.getCellData(i, "clntNo") == ""){
				$c.win.alert("매니저코드는 필수 입력 항목 입니다.");
				return false;
				break;
			}
			if(ds_manager.getCellData(i, "ctrtStDt") == ""){
				$c.win.alert("매니저의 적용일자FROM은  필수 입력 항목 입니다.");
				return false;
				break;
			}
			if(ds_manager.getCellData(i, "ctrtEndDt") == ""){
				$c.win.alert("매니저의 적용일자TO는  필수 입력 항목 입니다.");
				return false;
				break;
			}
		}
	}

    let confirm = await $c.win.confirm(MSG_CM_CRM_001); //저장하시겠습니까?
	if( confirm ){ 
    	//tr_save.Post();
        $c.sbm.execute(sbm_save);
	}
};

scwin.sbm_save_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);  // 성공적으로 저장하였습니다.
        scwin.btn_retrieve_onclick();
    }
};


//-------------------------------------------------------------------------
// function name : f_newSetting()
// function desc : 신규버튼 
//-------------------------------------------------------------------------
scwin.btn_new_onclick = function (e) {
    ds_results.removeAll();
    ds_results.insertRow();
    gr_results.setFocusedCell(0, 0);
    ds_results.setCellData(ds_results.getRowPosition(), "useYn", "1");
	ds_results.setCellData(ds_results.getRowPosition(), "coCd", "022"); //대성TLS 자회사 코드

    ds_clnt.removeAll();
    ds_manager.removeAll();

    $c.gus.cfEnableObjects([ ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy
                           , ed_clntNo_rslts, txt_clntNm_rslts
					       , acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2
                           , acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt
					       , ed_txt_insrTrf, ica_em_cutShedDt, em_insrTermFrom, em_insrTermTo, rd_useYn, ed_txt_rmk ]);
};

//-------------------------------------------------------------------------
// function name : f_update()
// function desc : 수정버튼 
//-------------------------------------------------------------------------
scwin.btn_modify_onclick = function (e) {
    $c.gus.cfEnableObjects([ ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy
                           , ed_clntNo_rslts, txt_clntNm_rslts
					       , acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2
                           , acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt
					       , ed_txt_insrTrf, ica_em_cutShedDt, em_insrTermFrom, em_insrTermTo, rd_useYn, ed_txt_rmk ]);
};

//-------------------------------------------------------------------------
// function name : f_cancel()
// function desc : 취소버튼 
//-------------------------------------------------------------------------
scwin.btn_cancle_onclick = function (e) {
    //ds_results.Undo(ds_results.RowPosition);
	//ds_clnt.Undo(ds_clnt.RowPosition);
	//ds_manager.Undo(ds_manager.RowPosition);

    var row1 = ds_results.getRowPosition();
    //추가등록정보만 삭제, 나머지는 상태값 삭제가 됨
    if (ds_results.getRowStatus(row1) == "C") {
        ds_results.removeRow(row1)
    } else {
        ds_results.undoRow(row1);
    }

    var row2 = ds_clnt.getRowPosition();
    //추가등록정보만 삭제, 나머지는 상태값 삭제가 됨
    if (ds_clnt.getRowStatus(row2) == "C") {
        ds_clnt.removeRow(row2)
    } else {
        ds_clnt.undoRow(row2);
    }

    var row3 = ds_manager.getRowPosition();
    //추가등록정보만 삭제, 나머지는 상태값 삭제가 됨
    if (ds_manager.getRowStatus(row3) == "C") {
        ds_manager.removeRow(row3)
    } else {
        ds_manager.undoRow(row3);
    }
};

scwin.f_addClnt = function () {
	if( ds_results.getRowCount() == 0 ) {
		$c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
	} else {
		if( ds_results.getCellData(ds_results.getRowPosition(), "clntNo") == "" ) {
			$c.win.alert("차량정보 중 소속거래처 정보가 없습니다.");
			return false;
		}
		if( scwin.retrieveDetailYn == "notYet" ) {
			//scwin.f_setDtheader_clnt();
		} else {
			ds_clnt.insertRow();
		}

        let rowIndex = ds_clnt.getRowCount()-1;
        gr_clnt.setFocusedCell(rowIndex, 0);

		ds_clnt.setCellData(ds_clnt.getRowPosition(), "selpchClsCd", "1"); // 매출거래처
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "clntNo", ds_results.getCellData(ds_results.getRowPosition(), "clntNo"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "clntNm", ds_results.getCellData(ds_results.getRowPosition(), "clntNm"));
		ds_clnt.setCellData(ds_clnt.getRowPosition(), "ctrtEndDt", "99991231");
	}
};

scwin.f_addManager = function () {
	if( ds_results.getRowCount() == 0 ) {
		$c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
	} else {
		if( scwin.retrieveDetailYn == "notYet" ) {
			//scwin.f_setDtheader_manager();
		} else {
			ds_manager.insertRow();
		}

        let rowIndex = ds_manager.getRowCount()-1;
        gr_manager.setFocusedCell(rowIndex, 0);

		ds_manager.setCellData(ds_manager.getRowPosition(), "selpchClsCd", "2"); //매입거래처
		ds_manager.setCellData(ds_manager.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
		ds_manager.setCellData(ds_manager.getRowPosition(), "ctrtEndDt", "99991231");
	}
};


scwin.btn_driverSerch_onclick = function (e) {
    var arrParam = new Array();
	var row = ds_manager.getRowPosition();
	if( ds_manager.getCellData(row, "clntNo") == "" ) {
		$c.win.alert("등록된 매니저가 없습니다. 매니저를 먼저 등록하십시오.");
		return false;
	}

    var data = {
          paramTitle : "기사정보"
        , clntNo : ds_manager.getCellData(row, "clntNo")
        , clntNm : ds_manager.getCellData(row, "clntNm")
        , callbackFn : scwin.f_vehclSearch_callBackFunc
    };

    var opts = {
          id : "smpPop"
        , popupName : "기사정보"
        , modal : true
        , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title : "Win pop"  //Layer pop
        , width : 530
        , height : 580
    };
};

scwin.btn_adptAmt_onclick = async function (e) {
    let confirm = await $c.win.confirm(MSG_CM_CRM_001); //저장하시겠습니까?
    if( confirm ) {
    	//ds_results.UseChangeInfo = "false";
    	//tr_saveMgntDt.Post();
    	//ds_results.UseChangeInfo = "true";
        $c.sbm.execute(sbm_saveMgntDt);
	}
};

scwin.sbm_saveMgntDt_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 )
    {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        scwin.btn_retrieve_onclick();
    }
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.udc_clntNo_openPopup('T');
};

scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.udc_clntNo_openPopup('T');
};

scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.udc_clntNo_openPopup('F');
};

scwin.udc_clntNo_openPopup = function (pClose) {
    let pCode = ed_clntNo.getValue();
    let pName = txt_clntNm.getValue();
    let pAllSearch = "F";
    let condition = "";
    if( cbx_cnd_chb_repClntYn.getValue() == 1 ) {
        condition = "RP";
    }

    udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc	    // XML상의 SELECT ID
                                ,pCode							// 화면에서의 ??? Code Element의	Value
                                ,pName							// 화면에서의 ??? Name Element의	Value
                                ,pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,'5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null							// Title순서
                                ,'150,170'  		    		// 보여주는 각 컬럼들의 폭
                                ,null							// 컬럼중에서 숨기는 컬럼 지정
                                ,condition						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                                ,null							// 윈도우 위치 Y좌표
                                ,null							// 윈도우 위치 X좌표
                                ,null							// 중복체크여부	("F")
                                ,pAllSearch						// 전체검색허용여부	("F")
                                ,"거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );
};

