// };
scwin.udc_clntNo_callBackFunc = function(ref){
    if (ref != null){
        $c.gus.cfSetReturnValue(ref, ed_clntNo, txt_clntNm);
    }
};

scwin.udc_vehclNoCd_onblurCodeEvent = function (e) {
    scwin.udc_vehclNoCd_openPopup('T');
};

scwin.udc_vehclNoCd_onviewchangeNameEvent = function (info) {
    scwin.udc_vehclNoCd_openPopup('T');
};

scwin.udc_vehclNoCd_onclickEvent = function (e) {
    scwin.udc_vehclNoCd_openPopup('F');
};

scwin.udc_vehclNoCd_openPopup = function (pClose) {
    let pCode = ed_vehclNoCd.getValue();
    let pName = txt_vehclNoNm.getValue();
    let pAllSearch = "T";

    udc_vehclNoCd.cfCommonPopUp(scwin.udc_vehclNoCd_callBackFunc	    // XML상의 SELECT ID	
                                ,pCode								    // 화면에서의 ??? Code Element의	Value
                                ,pName								    // 화면에서의 ??? Name Element의	Value
                                ,pClose								    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,'4'                   				    // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null                   			    // Title순서    
                                ,null                   			    // 보여주는 각 컬럼들의 폭  
                                ,null                   			    // 컬럼중에서 숨기는    컬럼 지정   
                                ,"022"                   		        // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                   			    // POP-UP뛰을때 원도우의    사용자 정의 폭
                                ,null                   			    // POP-UP뛰을때 우도우의    사용자 정의 높이    
                                ,null                   			    // 윈도우 위치 Y좌표    
                                ,null                   			    // 윈도우 위치 X좌표
                                ,null                   			    // 중복체크여부 ("F")
                                ,pAllSearch                 		    // 전체검색허용여부 ("F")
                                ,"차량번호조회,차량단축코드,차량번호"     // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );
};

scwin.udc_vehclNoCd_callBackFunc = function (rtnList) {
    if( rtnList != null ) {
        ed_vehclNoCd.setValue(rtnList[0]); // 코드
        txt_vehclNoNm.setValue(rtnList[1]); // 명
    }
    else {
        ed_vehclNoCd.setValue(""); // 코드
        txt_vehclNoNm.setValue(""); // 명
    }
};

scwin.udc_clntNo_rslts_onblurCodeEvent = function (e) {
    scwin.udc_clntNo_rslts_openPopup('T');
};

scwin.udc_clntNo_rslts_onviewchangeNameEvent = function (e) {
    scwin.udc_clntNo_rslts_openPopup('T');
};

scwin.udc_clntNo_rslts_onclickEvent = function (e) {
    scwin.udc_clntNo_rslts_openPopup('F');
