// 매출거래처 Grid
scwin.rowAddClntFunction = function () {
    if( ds_results.getRowCount() == 0 ) {
        $c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
        return false;
    }

    if (ds_results.getCellData(ds_results.getRowPosition(), "clntNm") == "") {
        $c.win.alert("차량정보 중 소속거래처 정보가 없습니다.");
        return false;
    }

    idx = ds_clnt.insertRow();
    ds_clnt.setCellData(idx, "clntNm", ds_results.getCellData(ds_results.getRowPosition(), "clntNm"));
    ds_clnt.setCellData(idx, "ctrtStDt", "");
    ds_clnt.setCellData(idx, "ctrtEndDt", "9999/12/31");
    gr_clnt.setFocusedCell(idx, 2);
};

scwin.rowDelClntFunction = function () {
    row = gr_clnt.getFocusedRowIndex();
    if (ds_clnt.getRowStatus(row) == "C") {
        ds_clnt.removeRow(row);
        return;
    }
    ds_clnt.setCellData(row, "chk", "1");
    ds_clnt.modifyRowStatus(row, "D");
};

scwin.cancelClntFunction = function () {
    row = gr_clnt.getFocusedRowIndex();
    if (ds_clnt.getRowStatus(row) == "C") {
        ds_clnt.removeRow(row);
        return;
    }
    ds_clnt.undoRow(gr_clnt.getFocusedRowIndex());
    gr_clnt.setFocusedCell(0, 0);
};

// 매니저 Grid
scwin.rowAddManageFunction = function () {
    if( ds_results.getRowCount() == 0 ) {
        $c.win.alert("차량정보가 없습니다. 신규버튼을 클릭하여 새로 등록하거나 조회하시기 바랍니다.");
        return false;
    }

    idx = ds_manager.insertRow();
    ds_manager.setCellData(idx, "clntNo", "");
    ds_manager.setCellData(idx, "clntNm", "");
    ds_manager.setCellData(idx, "ctrtStDt", "");
    ds_manager.setCellData(idx, "ctrtEndDt", "9999/12/31");
    gr_manager.setFocusedCell(idx, 8);
};

