    try{
        let colid = gr_manager.getColumnID(columnIndex);
        if(colid == "clntNo"){
            let clntNo = gr_manager.getCellData(rowIndex, "clntNo");
            if (clntNo == "") {
                gr_manager.setCellData(rowIndex, "clntNo", "");
                return false;
            }
            scwin.f_openCommonPopUp(5, clntNo, "", 'F', 'F',rowIndex);
        }
    } catch (e) {
       console.log("gr_results_onafteredit : " + e);
    }        
};
